class Solution:
    def subsets(self, nums: list[int]) -> list[list[int]]:
        ans, path = [], []

        def bt(i):
            if i == len(nums):
                ans.append(path[:])
                return
            bt(i + 1)
            path.append(nums[i])
            bt(i + 1)
            path.pop()

        bt(0)
        return ans

class Solution:
    def subsets(self, nums: list[int]) -> list[list[int]]:
        n = len(nums)
        out = []
        for mask in range(1 << n):
            sub = [nums[i] for i in range(n) if mask & (1 << i)]
            out.append(sub)
        return out

