class Solution:
    def subsets(self, nums: list[int]) -> list[list[int]]:
        out = [[]]                   # 从「只含空集」开始
        for x in nums:
            # 每加入新数 x:在已有所有子集后各复制一份并加上 x
            out += [s + [x] for s in out]
        return out
